<?php
namespace App\Models\Inventory; use Illuminate\Database\Eloquent\{Factories\HasFactory,Model,SoftDeletes}; use Illuminate\Database\Eloquent\Relations\{BelongsTo,HasMany};
class InventoryItem extends Model{use HasFactory,SoftDeletes; protected $guarded=[]; protected function casts():array{return ['is_active'=>'boolean','acquisition_date'=>'date','acquisition_value'=>'decimal:2'];} public function category():BelongsTo{return $this->belongsTo(InventoryCategory::class,'inventory_category_id');} public function unit():BelongsTo{return $this->belongsTo(InventoryMeasurementUnit::class,'inventory_measurement_unit_id');} public function primaryLocation():BelongsTo{return $this->belongsTo(InventoryLocation::class,'primary_location_id');} public function balances():HasMany{return $this->hasMany(InventoryBalance::class);} public function transactions():HasMany{return $this->hasMany(InventoryTransaction::class);} public function itemUnits():HasMany{return $this->hasMany(InventoryItemUnit::class);} public function getTotalQuantityAttribute():int{return (int)$this->balances()->sum('quantity');}}
